```typescript
describe("StarknetService.computeDeployAddress (real implementation)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  const withTestConfig = ConfigProvider.fromMap(
    new Map([
      ["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"],
      ["FALCON_ACCOUNT_CLASS_HASH", "0x0"],
    ]),
  )

  it("returns DeployPrecompute with address, salt, and constructorCalldata", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(withTestConfig)),
      ),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      const precompute = exit.value
      expect(typeof precompute.address).toBe("string")
      expect(precompute.address.startsWith("0x")).toBe(true)
      expect(typeof precompute.salt).toBe("string")
      expect(precompute.salt.startsWith("0x")).toBe(true)
      expect(precompute.constructorCalldata.length).toBeGreaterThan(0)
    }
  })

  it("two calls with same input produce different salts (randomness)", async () => {
    const run = () =>
      Effect.runPromiseExit(
        StarknetService.computeDeployAddress(mockPk).pipe(
          Effect.provide(StarknetService.Default),
          Effect.provide(Layer.setConfigProvider(withTestConfig)),
        ),
      )
    const exit1 = await run()
    const exit2 = await run()
    expect(Exit.isSuccess(exit1)).toBe(true)
    expect(Exit.isSuccess(exit2)).toBe(true)
    if (Exit.isSuccess(exit1) && Exit.isSuccess(exit2)) {
      // Different salts → different addresses
      expect(exit1.value.salt).not.toBe(exit2.value.salt)
      expect(exit1.value.address).not.toBe(exit2.value.address)
    }
  })

  it("fails when FALCON_ACCOUNT_CLASS_HASH config is missing", async () => {
    const partialConfig = ConfigProvider.fromMap(
      new Map([["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"]]),
    )
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(partialConfig)),
      ),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})
