## Task 4: Rewrite `StarknetService.ts` — All 6 Fixes

**Files:**
- Modify: `apps/demo/src/services/StarknetService.ts`

**Step 1: Rewrite the full StarknetService**

Replace `apps/demo/src/services/StarknetService.ts` entirely:

```typescript
import { Config, Effect, Schema } from "effect"
import {
  RpcProvider,
  Account,
  hash,
  CallData,
  stark,
  RpcError,
} from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
  InsufficientFundsError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey, DeployPrecompute } from "./types"
import { extractRpcErrorCode } from "./starknet-utils"

// STRK token contract on Starknet mainnet
const STRK_TOKEN_ADDRESS =
  "REDACTED"

export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      const classHash = yield* Config.string("FALCON_ACCOUNT_CLASS_HASH")
      const provider = new RpcProvider({ nodeUrl: rpcUrl })

      const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
        function* (packedPk: PackedPublicKey) {
          const constructorCalldata = CallData.compile({
            pk_packed: packedPk.slots,
          })
          const salt = stark.randomAddress()
          const address = hash.calculateContractAddressFromHash(
            salt,
            classHash,
            constructorCalldata,
            0,
          )
          return {
            address: Schema.decodeSync(ContractAddress)(address),
            salt,
            constructorCalldata: [...constructorCalldata],
          } satisfies DeployPrecompute
        },
      )

      const getBalance = Effect.fn("Starknet.getBalance")(
        function* (address: string) {
          return yield* Effect.tryPromise({
            try: async () => {
              const result = await provider.callContract({
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "balanceOf",
                calldata: [address],
              })
              return BigInt(result[0])
            },
            catch: (error) =>
              new StarknetRpcError({
                message: String(error),
                code: extractRpcErrorCode(error),
              }),
          })
        },
      )

      const deployAccount = Effect.fn("Starknet.deployAccount")(
        function* (precompute: DeployPrecompute, privateKey: string) {
          // Balance gate: check account has funds before deploying
          const balance = yield* Effect.tryPromise({
            try: async () => {
              const result = await provider.callContract({
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "balanceOf",
                calldata: [precompute.address],
              })
              return BigInt(result[0])
            },
            catch: (error) =>
              new StarknetRpcError({
                message: `Balance check failed: ${error}`,
                code: extractRpcErrorCode(error),
              }),
          })

          if (balance === 0n) {
            return yield* Effect.fail(
              new InsufficientFundsError({
                message:
                  "Account balance is 0 — fund the account before deploying",
                address: precompute.address,
                required: ">0",
              }),
            )
          }

          // starknet.js v9 Account constructor
          const account = new Account({
            provider,
            address: precompute.address,
            signer: privateKey,
          })

          const result = yield* Effect.tryPromise({
            try: () =>
              account.deployAccount({
                classHash,
                constructorCalldata: precompute.constructorCalldata,
                addressSalt: precompute.salt,
                contractAddress: precompute.address,
              }),
            catch: (error) =>
              new AccountDeployError({
                message: String(error),
              }),
          })

          yield* Effect.tryPromise({
            try: () =>
              provider.waitForTransaction(result.transaction_hash),
            catch: (error) =>
              new AccountDeployError({
                message: `Tx failed: ${error}`,
                txHash: result.transaction_hash,
              }),
          })

          return {
            txHash: Schema.decodeSync(TxHash)(result.transaction_hash),
            address: Schema.decodeSync(ContractAddress)(
              result.contract_address,
            ),
          }
        },
      )

      const waitForTx = Effect.fn("Starknet.waitForTx")(
        function* (txHash: string) {
          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(txHash),
            catch: (error) =>
              new StarknetRpcError({
                message: String(error),
                code: extractRpcErrorCode(error),
              }),
          })
        },
      )

      // NOTE: provider is NOT exposed — encapsulated within the service
      return {
        computeDeployAddress,
        getBalance,
        deployAccount,
        waitForTx,
      }
    }),
  },
) {}
```

