const makeDeployOrchestrationEffect = (registry: ReturnType<typeof Registry.make>) =>
  Effect.gen(function* () {
    registry.set(deployStepAtom, { step: "generating-keypair" })

    registry.set(deployStepAtom, { step: "packing" })
    const packedPk = MOCK_PACKED_PK

    registry.set(deployStepAtom, { step: "computing-address" })
    const precompute = yield* StarknetService.computeDeployAddress(packedPk)

    registry.set(deployStepAtom, { step: "awaiting-funds", address: precompute.address })
    const balance = yield* StarknetService.getBalance(precompute.address)

    registry.set(deployStepAtom, { step: "deploying", address: precompute.address })
    const result = yield* StarknetService.deployAccount(precompute, MOCK_PRIVATE_KEY)

    registry.set(deployStepAtom, {
      step: "deployed",
      address: result.address,
      txHash: result.txHash,
    })

    return { address: result.address, txHash: result.txHash, balance }
  })
```

