// apps/demo/src/services/starknet-utils.ts

import { RpcError } from "starknet"

/**
 * Extract a numeric RPC error code from a thrown starknet error.
 *
 * Priority:
 * 1. If error is an `RpcError` instance → use `.code` getter
 * 2. If error has a numeric `.code` property → use it
 * 3. If error has `.baseError.code` → use it
 * 4. Fallback → -1
 */
export function extractRpcErrorCode(error: unknown): number {
  if (error instanceof RpcError) {
    return error.code
  }
  if (typeof error === "object" && error !== null) {
    const obj = error as Record<string, unknown>
    if (typeof obj.code === "number") {
      return obj.code
    }
    if (
      typeof obj.baseError === "object" &&
      obj.baseError !== null &&
      typeof (obj.baseError as Record<string, unknown>).code === "number"
    ) {
      return (obj.baseError as Record<string, unknown>).code as number
    }
  }
  return -1
}
```

