const makeDeployOrchestrationEffect = (registry: ReturnType<typeof Registry.make>) =>
  Effect.gen(function* () {
    registry.set(deployStepAtom, { step: "generating-keypair" })

    registry.set(deployStepAtom, { step: "packing" })
    const packedPk = MOCK_PACKED_PK

